import Slider from "react-slick";

const HeroSlider = () => {
  const settings = {
    dots: true,
    infinite: true,
    speed: 800,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 3000,
    arrows: false,
  };

  const slides = [
    {
      img: "/images/headphone.png",
      offer: "Limited Time Offer 30% Off",
      title: "Experience Pure Sound - Your Perfect Headphones Awaits!",
    },
    {
      img: "/images/shoes.png",
      offer: "Flat 40% Discount",
      title: "Step Up Your Style With Premium Shoes",
    },
    {
      img: "/images/laptop.png",
      offer: "Save Big on Laptops",
      title: "Powerful Performance for Work & Play!",
    },
  ];

  return (
    <div className="w-full max-w-6xl mx-auto mt-6">
      <Slider {...settings}>
        {slides.map((slide, index) => (
          <div
            key={index}
            className="flex flex-col md:flex-row items-center justify-center gap-6 p-6 bg-gray-100 rounded-2xl"
          >
            {/* Product Image */}
            <img
              src={slide.img}
              alt="product"
              className="w-60 h-60 object-contain"
            />

            {/* Text Content */}
            <div className="text-center md:text-left">
              <p className="text-red-500 font-semibold">{slide.offer}</p>
              <h2 className="text-2xl font-bold text-gray-800 my-2">
                {slide.title}
              </h2>
              <div className="flex gap-4 justify-center md:justify-start mt-4">
                <button className="bg-orange-500 text-white px-5 py-2 rounded-lg hover:bg-orange-600">
                  Buy now
                </button>
                <button className="text-gray-700 hover:underline">
                  Find more →
                </button>
              </div>
            </div>
          </div>
        ))}
      </Slider>
    </div>
  );
};

export default HeroSlider;
